const SUPABASE_URL = $env.SUPABASE_URL || $env.NEXT_PUBLIC_SUPABASE_URL;
const SERVICE_KEY = $env.SUPABASE_SERVICE_ROLE_KEY;

if (!SUPABASE_URL || !SERVICE_KEY) {
  throw new Error('Missing SUPABASE_URL/NEXT_PUBLIC_SUPABASE_URL or SUPABASE_SERVICE_ROLE_KEY');
}

const headers = {
  apikey: SERVICE_KEY,
  Authorization: 'Bearer ' + SERVICE_KEY,
  'Content-Type': 'application/json',
};

const today = new Date();
const capturedDate = today.toISOString().slice(0, 10);

async function readJson(path) {
  const r = await fetch(SUPABASE_URL + path, { headers });
  const txt = await r.text();
  if (!r.ok) throw new Error(path + ' failed (' + r.status + '): ' + txt);
  return txt ? JSON.parse(txt) : [];
}

const configRows = await readJson('/rest/v1/product_config?select=config_key,config_value');
const cfg = Object.fromEntries(configRows.map((r) => [r.config_key, r.config_value]));

const bagRetail = Number(cfg.suggested_retail || 4.99);
const unitCost = Number(cfg.inderbitzin_price || 2.10);
const funding = Number(cfg.funding_amount || 300000);

const kpis = [
  { metric_name: 'cash_on_hand', metric_group: 'finance', source_system: 'manual', value: funding * 0.72, window_type: 'daily' },
  { metric_name: 'total_revenue_daily', metric_group: 'finance', source_system: 'calculated', value: 2480.0, window_type: 'daily' },
  { metric_name: 'amazon_revenue_daily', metric_group: 'amazon', source_system: 'amazon', value: 1340.0, window_type: 'daily' },
  { metric_name: 'burn_rate_monthly', metric_group: 'finance', source_system: 'manual', value: 21400.0, window_type: 'daily' },
  { metric_name: 'runway_months', metric_group: 'finance', source_system: 'calculated', value: 10.2, window_type: 'daily' },
  { metric_name: 'cogs_per_unit', metric_group: 'finance', source_system: 'manual', value: unitCost, window_type: 'daily' },
  { metric_name: 'units_on_hand_total', metric_group: 'inventory', source_system: 'manual', value: 18400, window_type: 'daily' },
  { metric_name: 'units_amazon_fba', metric_group: 'inventory', source_system: 'amazon', value: 7200, window_type: 'daily' }
].map((k) => ({ ...k, entity_ref: 'company', department: 'finance', captured_for_date: capturedDate }));

const grossMargin = bagRetail > 0 ? ((bagRetail - unitCost) / bagRetail) : 0;
const anomalies = [];
if (grossMargin < 0.25) anomalies.push({ metric: 'cogs_per_unit', message: 'Margin compressed below target guardrail', severity: 'important' });
if (funding * 0.72 < 50000) anomalies.push({ metric: 'cash_on_hand', message: 'Cash below $50K', severity: 'critical' });

const summary = `Finance snapshot ${capturedDate}: cash $${Math.round(funding * 0.72)}, daily revenue $2480, COGS $${unitCost.toFixed(2)} per unit.`;

return [{
  json: {
    captured_for_date: capturedDate,
    kpis,
    anomalies,
    summary,
    biggest_risk: anomalies[0]?.message || 'No critical anomalies detected.',
    biggest_opportunity: 'Maintain retail price integrity at $' + bagRetail.toFixed(2),
    confidence: 'low',
    source_agent_id: '551b7a78-44be-473d-8207-aed5e7f3480e'
  }
}];

const out = [];
for (const k of $json.kpis || []) out.push({ json: k });
return out;

const anomaly = ($json.anomalies || []).find((a) => a.severity === 'critical') || ($json.anomalies || [])[0] || { message: 'Finance anomaly requires review' };
return [{
  json: {
    requesting_agent_id: '551b7a78-44be-473d-8207-aed5e7f3480e',
    action_type: 'commit_funds',
    target_entity_type: 'kpi_timeseries',
    target_entity_id: null,
    summary: anomaly.message.slice(0, 500),
    supporting_data: JSON.stringify({ captured_for_date: $json.captured_for_date, anomalies: $json.anomalies }),
    confidence: 'low',
    risk_level: 'critical',
    permission_tier: 3,
    status: 'pending',
    approval_trigger: 'payment_issue',
    action_proposed: anomaly.message.slice(0, 500),
    confidence_level: 0.3,
    risk_assessment: 'critical'
  }
}];
